import{_ as s,o as e,c as i,ag as t}from"./chunks/framework.DlJzNSsD.js";const u=JSON.parse('{"title":"Installation and updates","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/installation.md","filePath":"getting-started/installation.md","lastUpdated":1778881760000}'),n={name:"getting-started/installation.md"};function l(r,a,h,p,o,d){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="installation-and-updates" tabindex="-1">Installation and updates <a class="header-anchor" href="#installation-and-updates" aria-label="Permalink to &quot;Installation and updates&quot;">​</a></h1><p>ClawTerm is <strong>macOS-only</strong> — universal builds for Apple Silicon and Intel.</p><h2 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-label="Permalink to &quot;Install&quot;">​</a></h2><p>One-liner installer (downloads the latest DMG, verifies the SHA-256 checksum against the release&#39;s <code>checksums-universal-apple-darwin.txt</code>, copies <code>ClawTerm.app</code> into <code>/Applications</code>, and clears the quarantine flag):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/clawterm/clawterm/main/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p>If you&#39;d rather install by hand, download <code>ClawTerm_&lt;version&gt;_universal.dmg</code> from the <a href="https://github.com/clawterm/clawterm/releases/latest" target="_blank" rel="noreferrer">latest release</a> — a single universal build that runs on both Apple Silicon and Intel Macs.</p><p>Mount the DMG and drag <code>ClawTerm.app</code> into <code>/Applications</code>.</p><blockquote><p><strong>Gatekeeper note:</strong> ClawTerm is not yet Apple-notarized. If macOS refuses to launch it, clear the quarantine flag once:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xattr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Applications/ClawTerm.app</span></span></code></pre></div><p>Tracking issue: <a href="https://github.com/clawterm/clawterm/issues/378" target="_blank" rel="noreferrer">#378</a>.</p></blockquote><h3 id="building-from-source" tabindex="-1">Building from source <a class="header-anchor" href="#building-from-source" aria-label="Permalink to &quot;Building from source&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/clawterm/clawterm.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clawterm</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tauri</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><p>Requirements:</p><ul><li><a href="https://rustup.rs/" target="_blank" rel="noreferrer">Rust</a></li><li><a href="https://nodejs.org/" target="_blank" rel="noreferrer">Node.js</a> 18+</li><li>Tauri system dependencies — see the <a href="https://v2.tauri.app/start/prerequisites/" target="_blank" rel="noreferrer">Tauri prerequisites guide</a></li></ul><p>The built binary lands in <code>src-tauri/target/release/</code>.</p><h2 id="verifying-checksums-manually" tabindex="-1">Verifying checksums manually <a class="header-anchor" href="#verifying-checksums-manually" aria-label="Permalink to &quot;Verifying checksums manually&quot;">​</a></h2><p>The release ships a single checksums file, <code>checksums-universal-apple-darwin.txt</code>. Verify your DMG against it:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shasum</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 256</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checksums-universal-apple-darwin.txt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ignore-missing</span></span></code></pre></div><p>The one-liner installer does this automatically and aborts on mismatch.</p><h2 id="updates" tabindex="-1">Updates <a class="header-anchor" href="#updates" aria-label="Permalink to &quot;Updates&quot;">​</a></h2><p>ClawTerm checks for updates automatically once an hour by default. When a new version is available, a dialog appears with the release notes and an <strong>Install</strong> button.</p><p>Update behaviour is controlled by the <code>updates</code> section in <code>config.json</code> — see <a href="./../reference/configuration#updates">configuration.md → updates</a> for the full schema. Summary:</p><ul><li><code>updates.autoCheck</code> — turn auto-checking on or off</li><li><code>updates.checkIntervalMs</code> — how often to poll (5 minutes to 24 hours)</li><li><code>updates.autoInstall</code> — silently install updates without prompting</li></ul><p>You can also trigger a manual update check from the settings page.</p><h3 id="re-running-the-install-script" tabindex="-1">Re-running the install script <a class="header-anchor" href="#re-running-the-install-script" aria-label="Permalink to &quot;Re-running the install script&quot;">​</a></h3><p>Running the same one-liner again performs an in-place upgrade:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/clawterm/clawterm/main/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p>If the installed version already matches the latest release, the script exits without doing any work.</p><h2 id="uninstalling" tabindex="-1">Uninstalling <a class="header-anchor" href="#uninstalling" aria-label="Permalink to &quot;Uninstalling&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/clawterm/clawterm/main/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --uninstall</span></span></code></pre></div><p>This removes <code>/Applications/ClawTerm.app</code> and prompts before deleting <code>~/.config/clawterm</code> (so your config survives unless you say otherwise).</p><p><strong>Manual cleanup paths:</strong></p><table tabindex="0"><thead><tr><th>Item</th><th>Location</th></tr></thead><tbody><tr><td>App bundle</td><td><code>/Applications/ClawTerm.app</code></td></tr><tr><td>Config</td><td><code>~/.config/clawterm/</code></td></tr></tbody></table>`,31)])])}const k=s(n,[["render",l]]);export{u as __pageData,k as default};
